#include <vector>
#include <algorithm>

std::vector<int> filter_even(const std::vector<int>& nums) {
    std::vector<int> result;
    std::copy_if(nums.begin(), nums.end(), std::back_inserter(result), [](int n) {
        return n % 2 == 0;
    });
    return result;
}
